import{_ as a,l as e,k as t,ad as o}from"./chunks/framework.CZ3uBn-2.js";const v=JSON.parse('{"title":"10 加减速判断","description":"","frontmatter":{"cate":["运动的描述","加速度"],"type":"1,"},"headers":[],"relativePath":"gaozhong/物理/合集/01 必修一/01 运动的描述/10 基础课-加减速判断.md","filePath":"gaozhong/物理/合集/01 必修一/01 运动的描述/10 基础课-加减速判断.md","lastUpdated":1718435780000}'),i={name:"gaozhong/物理/合集/01 必修一/01 运动的描述/10 基础课-加减速判断.md"},l=o('<h1 id="_10-加减速判断" tabindex="-1">10 加减速判断 <a class="header-anchor" href="#_10-加减速判断" aria-label="Permalink to &quot;10 加减速判断&quot;">​</a></h1><h2 id="速度与什么有关" tabindex="-1">速度与什么有关 <a class="header-anchor" href="#速度与什么有关" aria-label="Permalink to &quot;速度与什么有关&quot;">​</a></h2><img src="http://my-course-public.oss-cn-shanghai.aliyuncs.com/public/assets/gaozhong_physics_3/physics_242.png"><h2 id="a、v、-∆v-关系总结" tabindex="-1">a、v、 ∆𝑣 关系总结 <a class="header-anchor" href="#a、v、-∆v-关系总结" aria-label="Permalink to &quot;a、v、 ∆𝑣 关系总结&quot;">​</a></h2><p>v 与 a 有关，但是只靠 a 不能决定 v。</p><p>a 与 v、∆𝒗 均无关</p><p>∆𝒗 与 a 有关，a 可以决定 ∆𝒗 的方向，但不能决定大小</p><h2 id="加减速判断" tabindex="-1">加减速判断 <a class="header-anchor" href="#加减速判断" aria-label="Permalink to &quot;加减速判断&quot;">​</a></h2><p>av 同向必加速，av 反向必减速。</p><p>加减速判断：同加反减。</p><p>加减速判断必须同时看 av，单独靠 a 和 v 都无法判断！</p><h2 id="加速度的增大减小" tabindex="-1">加速度的增大减小 <a class="header-anchor" href="#加速度的增大减小" aria-label="Permalink to &quot;加速度的增大减小&quot;">​</a></h2><p>判断加减速只看 a 方向，不看 a 大小变化。</p><p>av同向，即使a减小，速度也增加，只不过增加的越来越慢。</p><p>av反向，即使a增加，速度也减小，只不过减小的越来越快。</p><h2 id="核心三句话" tabindex="-1">核心三句话 <a class="header-anchor" href="#核心三句话" aria-label="Permalink to &quot;核心三句话&quot;">​</a></h2><ol><li>a=0物体未必静止，还可能做匀速直线运动</li><li>只知道a的增减，无法判断v的增减</li><li>只知道a的方向，无法判断v的方向</li></ol><h2 id="av反向的运动全过程" tabindex="-1">av反向的运动全过程 <a class="header-anchor" href="#av反向的运动全过程" aria-label="Permalink to &quot;av反向的运动全过程&quot;">​</a></h2><p>第一阶段：减速，减速到0</p><p>第二阶段：从0反向加速，av同向</p><h2 id="匀变速直线运动" tabindex="-1">匀变速直线运动 <a class="header-anchor" href="#匀变速直线运动" aria-label="Permalink to &quot;匀变速直线运动&quot;">​</a></h2><p>a不变的直线运动</p><p>速度均匀变化</p><p>三种匀变速直线运动：</p><ol><li>加速</li><li>减速到0停止</li><li>减速到0然后反向加速</li></ol>',25),r=[l];function h(s,n,p,c,_,d){return t(),e("div",null,r)}const m=a(i,[["render",h]]);export{v as __pageData,m as default};
